#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding medical-error-report (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    reporter_first_name:string! \
    reporter_last_name:string! \
    reporter_role:string! \
    reporter_department:string! \
    reporter_contact_phone:string! \
    reporter_contact_email:string! \
    facility_name:string! \
    facility_ward:string! \
    report_date:date \
    anonymous_report:string! \
    --htmx

cargo loco generate scaffold assessment_incident_details \
    assessment:references \
    incident_date:date \
    incident_time:string \
    discovery_date:date \
    discovery_time:string \
    location_type:string! \
    location_details:text! \
    incident_summary:text! \
    incident_witnessed:string! \
    witness_details:text! \
    shift_type:string! \
    staffing_level:string! \
    --htmx

cargo loco generate scaffold assessment_patient_involvement \
    assessment:references \
    patient_involved:string! \
    patient_first_name:string! \
    patient_last_name:string! \
    patient_nhs_number:string! \
    patient_date_of_birth:date \
    patient_sex:string! \
    patient_age_at_incident:int \
    patient_informed:string! \
    patient_informed_date:date \
    patient_informed_by:string! \
    duty_of_candour_applies:string! \
    duty_of_candour_completed:string! \
    --htmx

cargo loco generate scaffold assessment_error_classification \
    assessment:references \
    error_type:string! \
    error_type_details:text! \
    medication_error_stage:string! \
    who_severity:string! \
    ncc_merp_category:string! \
    preventability:string! \
    recurrence_likelihood:string! \
    --htmx

cargo loco generate scaffold assessment_contributing_factors \
    assessment:references \
    staff_fatigue:string! \
    inadequate_training:string! \
    communication_failure:string! \
    communication_failure_details:text! \
    handover_failure:string! \
    equipment_failure:string! \
    equipment_failure_details:text! \
    environmental_factors:string! \
    environmental_details:text! \
    policy_not_followed:string! \
    policy_details:text! \
    workload_pressure:string! \
    patient_factors:string! \
    patient_factors_details:text! \
    other_factors:text! \
    --htmx

cargo loco generate scaffold assessment_immediate_actions \
    assessment:references \
    patient_assessed:string! \
    treatment_provided:string! \
    treatment_details:text! \
    error_contained:string! \
    containment_details:text! \
    senior_staff_notified:string! \
    senior_staff_name:string! \
    senior_staff_role:string! \
    risk_team_notified:string! \
    additional_monitoring:string! \
    monitoring_details:text! \
    immediate_actions_summary:text! \
    --htmx

cargo loco generate scaffold assessment_patient_outcome \
    assessment:references \
    harm_reached_patient:string! \
    harm_level:string! \
    harm_description:text! \
    additional_treatment_required:string! \
    additional_treatment_details:text! \
    extended_hospital_stay:string! \
    extra_days:int \
    readmission_required:string! \
    permanent_disability:string! \
    disability_details:text! \
    patient_died:string! \
    death_date:date \
    outcome_notes:text! \
    --htmx

cargo loco generate scaffold assessment_root_cause_analysis \
    assessment:references \
    rca_conducted:string! \
    rca_date:date \
    rca_lead:string! \
    rca_team_members:text! \
    root_cause_category:string! \
    root_cause_description:text! \
    five_whys_analysis:text! \
    fishbone_factors:text! \
    system_vulnerabilities:text! \
    similar_incidents:string! \
    similar_incidents_details:text! \
    rca_findings_summary:text! \
    --htmx

cargo loco generate scaffold assessment_corrective_actions \
    assessment:references \
    immediate_corrective_actions:text! \
    long_term_corrective_actions:text! \
    policy_change_required:string! \
    policy_change_details:text! \
    training_required:string! \
    training_details:text! \
    equipment_change_required:string! \
    equipment_change_details:text! \
    process_redesign_required:string! \
    process_redesign_details:text! \
    responsible_person:string! \
    target_completion_date:date \
    actions_status:string! \
    --htmx

cargo loco generate scaffold assessment_reporting_followup \
    assessment:references \
    internal_reference:string! \
    reported_to_datix:string! \
    datix_reference:string! \
    reported_to_nrls:string! \
    nrls_reference:string! \
    reported_to_cqc:string! \
    reported_to_hsib:string! \
    reported_to_coroner:string! \
    safeguarding_referral:string! \
    lessons_learned:text! \
    shared_with_team:string! \
    follow_up_review_date:date \
    follow_up_reviewer:string! \
    final_status:string! \
    closure_date:date \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    who_severity:string! \
    ncc_merp_category:string! \
    overall_risk_level:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
